import{_ as t,o as i,c as a,ag as s}from"./chunks/framework.Dn0B0GT3.js";const u=JSON.parse('{"title":"Security Model","description":"","frontmatter":{"outline":[2,3]},"headers":[],"relativePath":"internals/security.md","filePath":"internals/security.md"}'),n={name:"internals/security.md"};function r(o,e,l,d,c,h){return i(),a("div",null,[...e[0]||(e[0]=[s(`<h1 id="security-model" tabindex="-1">Security Model <a class="header-anchor" href="#security-model" aria-label="Permalink to &quot;Security Model&quot;">​</a></h1><p>ShellPort is designed with security-first principles, implementing multiple layers of protection for encrypted terminal sessions. This page documents the complete security architecture.</p><h2 id="encryption-layers" tabindex="-1">Encryption Layers <a class="header-anchor" href="#encryption-layers" aria-label="Permalink to &quot;Encryption Layers&quot;">​</a></h2><h3 id="per-session-cryptographic-salt" tabindex="-1">Per-Session Cryptographic Salt <a class="header-anchor" href="#per-session-cryptographic-salt" aria-label="Permalink to &quot;Per-Session Cryptographic Salt&quot;">​</a></h3><p>Each session derives a unique cryptographic salt that prevents precomputation attacks:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>salt = SHA-256(server_nonce || client_nonce || secret_prefix)</span></span></code></pre></div><ul><li><strong>Server Nonce</strong> — Random 32-byte nonce generated by the server</li><li><strong>Client Nonce</strong> — Random 32-byte nonce generated by the client</li><li><strong>Secret Prefix</strong> — Derived from the URL fragment secret</li></ul><p>This ensures that even if an attacker knows the secret, they cannot precompute session keys.</p><h3 id="key-derivation-pbkdf2" tabindex="-1">Key Derivation (PBKDF2) <a class="header-anchor" href="#key-derivation-pbkdf2" aria-label="Permalink to &quot;Key Derivation (PBKDF2)&quot;">​</a></h3><p>The session encryption key is derived using PBKDF2 with high iteration count:</p><table tabindex="0"><thead><tr><th>Parameter</th><th>Value</th></tr></thead><tbody><tr><td>Algorithm</td><td>PBKDF2-SHA-256</td></tr><tr><td>Iterations</td><td>100,000</td></tr><tr><td>Salt</td><td>Per-session unique (from nonces)</td></tr><tr><td>Output Length</td><td>256 bits (32 bytes)</td></tr></tbody></table><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> key</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> await</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> crypto.subtle.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">deriveKey</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  { name: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;PBKDF2&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, salt, iterations: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">100000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, hash: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;SHA-256&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  baseKey,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  { name: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;AES-GCM&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, length: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">256</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> },</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;encrypt&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;decrypt&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><h3 id="aes-256-gcm-encryption" tabindex="-1">AES-256-GCM Encryption <a class="header-anchor" href="#aes-256-gcm-encryption" aria-label="Permalink to &quot;AES-256-GCM Encryption&quot;">​</a></h3><p>All terminal data is encrypted using AES-256-GCM, which provides both confidentiality and authenticity:</p><table tabindex="0"><thead><tr><th>Property</th><th>Value</th></tr></thead><tbody><tr><td>Cipher</td><td>AES-256</td></tr><tr><td>Mode</td><td>GCM (Galois/Counter Mode)</td></tr><tr><td>IV Size</td><td>12 bytes (96 bits)</td></tr><tr><td>Tag Size</td><td>16 bytes (128 bits)</td></tr><tr><td>Key Size</td><td>32 bytes (256 bits)</td></tr></tbody></table><p>Each message is encrypted with a fresh random IV:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[12-byte IV][AES-GCM ciphertext][16-byte auth tag]</span></span></code></pre></div><h3 id="iv-initialization-vector" tabindex="-1">IV (Initialization Vector) <a class="header-anchor" href="#iv-initialization-vector" aria-label="Permalink to &quot;IV (Initialization Vector)&quot;">​</a></h3><ul><li><strong>Size</strong> — 12 bytes (96 bits) per message</li><li><strong>Generation</strong> — Cryptographically secure random bytes</li><li><strong>Uniqueness</strong> — Never reused within a session</li><li><strong>Purpose</strong> — Provides semantic security; same plaintext encrypts to different ciphertext</li></ul><h2 id="authentication-mechanisms" tabindex="-1">Authentication Mechanisms <a class="header-anchor" href="#authentication-mechanisms" aria-label="Permalink to &quot;Authentication Mechanisms&quot;">​</a></h2><h3 id="proof-of-knowledge-protocol" tabindex="-1">Proof-of-Knowledge Protocol <a class="header-anchor" href="#proof-of-knowledge-protocol" aria-label="Permalink to &quot;Proof-of-Knowledge Protocol&quot;">​</a></h3><p>ShellPort uses a mutual nonce exchange for authentication:</p><ol><li><strong>Server generates</strong> a random challenge nonce</li><li><strong>Server encrypts</strong> its own nonce with the derived session key</li><li><strong>Client decrypts</strong> and returns the nonce</li><li><strong>Server verifies</strong> the returned nonce matches</li></ol><p>This proves the client possesses the correct session key without transmitting it.</p><h3 id="totp-two-factor-authentication" tabindex="-1">TOTP Two-Factor Authentication <a class="header-anchor" href="#totp-two-factor-authentication" aria-label="Permalink to &quot;TOTP Two-Factor Authentication&quot;">​</a></h3><p>ShellPort implements RFC 6238 Time-based One-Time Passwords:</p><table tabindex="0"><thead><tr><th>Parameter</th><th>Value</th></tr></thead><tbody><tr><td>Algorithm</td><td>HMAC-SHA-1</td></tr><tr><td>Digits</td><td>6</td></tr><tr><td>Period</td><td>30 seconds</td></tr><tr><td>Window</td><td>±1 (90 second total)</td></tr></tbody></table><h4 id="setup-flow" tabindex="-1">Setup Flow <a class="header-anchor" href="#setup-flow" aria-label="Permalink to &quot;Setup Flow&quot;">​</a></h4><ol><li>Server generates a random 160-bit secret</li><li>Secret is encoded as a base32 string</li><li>Server renders a QR code in the terminal for scanning</li><li>Client stores the secret for future verification</li></ol><h4 id="qr-code-format" tabindex="-1">QR Code Format <a class="header-anchor" href="#qr-code-format" aria-label="Permalink to &quot;QR Code Format&quot;">​</a></h4><p>The QR code contains an <code>otpauth://</code> URI:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>otpauth://totp/ShellPort:user@host?secret=JBSWY3DPEHPK3PXP&amp;issuer=ShellPort</span></span></code></pre></div><h4 id="verification" tabindex="-1">Verification <a class="header-anchor" href="#verification" aria-label="Permalink to &quot;Verification&quot;">​</a></h4><ul><li>User enters 6-digit code from their authenticator app</li><li>Server computes expected TOTP using stored secret</li><li>Code is valid if it matches within ±1 period (clock drift tolerance)</li></ul><h4 id="supported-authenticators" tabindex="-1">Supported Authenticators <a class="header-anchor" href="#supported-authenticators" aria-label="Permalink to &quot;Supported Authenticators&quot;">​</a></h4><ul><li>Google Authenticator</li><li>Authy</li><li>1Password</li><li>Any RFC 6238 compliant TOTP app</li></ul><h3 id="nonce-exchange-sequence" tabindex="-1">Nonce Exchange Sequence <a class="header-anchor" href="#nonce-exchange-sequence" aria-label="Permalink to &quot;Nonce Exchange Sequence&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Browser                          Server</span></span>
<span class="line"><span>  │                                │</span></span>
<span class="line"><span>  │  1. Server sends nonce         │</span></span>
<span class="line"><span>  │◀──────────────────────────────│</span></span>
<span class="line"><span>  │                                │</span></span>
<span class="line"><span>  │  2. Client sends nonce         │</span></span>
<span class="line"><span>  │──────────────────────────────▶│</span></span>
<span class="line"><span>  │  (per-session key derived)     │</span></span>
<span class="line"><span>  │                                │</span></span>
<span class="line"><span>  │  3. TOTP challenge (if enabled)│</span></span>
<span class="line"><span>  │◀──────────────────────────────│</span></span>
<span class="line"><span>  │                                │</span></span>
<span class="line"><span>  │  4. TOTP code response         │</span></span>
<span class="line"><span>  │──────────────────────────────▶│──▶ Verify code</span></span>
<span class="line"><span>  │                                │</span></span></code></pre></div><h2 id="transport-security" tabindex="-1">Transport Security <a class="header-anchor" href="#transport-security" aria-label="Permalink to &quot;Transport Security&quot;">​</a></h2><h3 id="url-fragment-secret-transport" tabindex="-1">URL Fragment Secret Transport <a class="header-anchor" href="#url-fragment-secret-transport" aria-label="Permalink to &quot;URL Fragment Secret Transport&quot;">​</a></h3><p>The encryption secret travels in the URL fragment (<code>#secret</code>):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://localhost:7681/#K7x9Pq2mNvLs8Yt3W</span></span></code></pre></div><ul><li><strong>Never sent to server</strong> — URL fragment is client-side only</li><li><strong>Browser History</strong> — May be stored in browser history</li><li><strong>Referer Header</strong> — Not included in HTTP requests</li><li><strong>Server Logs</strong> — Not visible in server access logs</li></ul><h3 id="websocket-security" tabindex="-1">WebSocket Security <a class="header-anchor" href="#websocket-security" aria-label="Permalink to &quot;WebSocket Security&quot;">​</a></h3><ul><li><strong>Subprotocol Versioning</strong> — Enforced protocol version in WebSocket handshake</li><li><strong>Origin Validation</strong> — Strict same-origin enforcement</li><li><strong>Localhost Bypass</strong> — Requires <code>--dev</code> flag to relax origin checks</li></ul><h3 id="security-headers" tabindex="-1">Security Headers <a class="header-anchor" href="#security-headers" aria-label="Permalink to &quot;Security Headers&quot;">​</a></h3><p>The HTTP responses include security headers:</p><table tabindex="0"><thead><tr><th>Header</th><th>Value</th><th>Purpose</th></tr></thead><tbody><tr><td>Content-Security-Policy</td><td>strict</td><td>Prevent XSS injections</td></tr><tr><td>X-Frame-Options</td><td>SAMEORIGIN</td><td>Prevent clickjacking</td></tr><tr><td>X-Content-Type-Options</td><td>nosniff</td><td>Prevent MIME sniffing</td></tr><tr><td>Referrer-Policy</td><td>strict-origin</td><td>Control referrer information</td></tr></tbody></table><h3 id="input-validation" tabindex="-1">Input Validation <a class="header-anchor" href="#input-validation" aria-label="Permalink to &quot;Input Validation&quot;">​</a></h3><ul><li><strong>Bounds Checking</strong> — All control messages validated before processing</li><li><strong>Buffer Limits</strong> — OSC/DCS sequences capped at 64KB</li><li><strong>Type Validation</strong> — Message types checked before dispatch</li></ul><h2 id="terminal-security-features" tabindex="-1">Terminal Security Features <a class="header-anchor" href="#terminal-security-features" aria-label="Permalink to &quot;Terminal Security Features&quot;">​</a></h2><h3 id="clipboard-operations-osc-52" tabindex="-1">Clipboard Operations (OSC 52) <a class="header-anchor" href="#clipboard-operations-osc-52" aria-label="Permalink to &quot;Clipboard Operations (OSC 52)&quot;">​</a></h3><p>Clipboard read/write operations require user confirmation:</p><ul><li><strong>Default: Ask</strong> — User prompted to approve each clipboard operation</li><li><strong>Configurable</strong> — Can be disabled via server configuration</li><li><strong>Timeout</strong> — Operations time out after 10 seconds</li></ul><h3 id="environment-variable-filtering" tabindex="-1">Environment Variable Filtering <a class="header-anchor" href="#environment-variable-filtering" aria-label="Permalink to &quot;Environment Variable Filtering&quot;">​</a></h3><p>Only whitelisted environment variables are passed to the PTY:</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> ALLOWED_ENV</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  &#39;TERM&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;COLORTERM&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;LANG&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;LC_*&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  &#39;SHELL&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;HOME&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;USER&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;PATH&#39;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">];</span></span></code></pre></div><p>Blocked variables include:</p><ul><li><code>SHELLPORT_*</code> internal variables</li><li><code>WS_*</code> WebSocket variables</li><li><code>SECRET</code>, <code>PASSWORD</code>, <code>TOKEN</code> patterns</li></ul><h3 id="connection-approval-mode" tabindex="-1">Connection Approval Mode <a class="header-anchor" href="#connection-approval-mode" aria-label="Permalink to &quot;Connection Approval Mode&quot;">​</a></h3><p>Interactive approval requires manual confirmation:</p><ul><li><strong>Default: ON</strong> — Server operator must approve connections</li><li><strong>Timeout</strong> — 30 second timeout for approval prompt</li><li><strong>Rejection</strong> — Connection dropped if denied or timeout</li><li><strong>Override</strong> — Available via <code>--no-approval</code> flag</li></ul><h3 id="rate-limiting" tabindex="-1">Rate Limiting <a class="header-anchor" href="#rate-limiting" aria-label="Permalink to &quot;Rate Limiting&quot;">​</a></h3><p>Brute-force protection against authentication attempts:</p><table tabindex="0"><thead><tr><th>Limit</th><th>Window</th><th>Scope</th></tr></thead><tbody><tr><td>5 attempts</td><td>1 minute</td><td>Per IP address</td></tr></tbody></table><h3 id="session-limits" tabindex="-1">Session Limits <a class="header-anchor" href="#session-limits" aria-label="Permalink to &quot;Session Limits&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Limit</th><th>Reason</th></tr></thead><tbody><tr><td>10 concurrent sessions</td><td>Resource management</td></tr><tr><td>Per-session unique key</td><td>Isolation</td></tr></tbody></table><h3 id="no-telemetry" tabindex="-1">No Telemetry <a class="header-anchor" href="#no-telemetry" aria-label="Permalink to &quot;No Telemetry&quot;">​</a></h3><ul><li><strong>Zero external network calls</strong> — All functionality is local</li><li><strong>No analytics</strong> — No tracking or telemetry</li><li><strong>No CDN dependencies</strong> — Everything bundled inline</li></ul><h2 id="security-modes" tabindex="-1">Security Modes <a class="header-anchor" href="#security-modes" aria-label="Permalink to &quot;Security Modes&quot;">​</a></h2><p>ShellPort supports four security configurations:</p><table tabindex="0"><thead><tr><th>Mode</th><th>Command</th><th>Encryption</th><th>TOTP</th><th>Approval</th></tr></thead><tbody><tr><td><strong>Full Security</strong></td><td><code>shellport server</code></td><td>AES-256-GCM</td><td>Required</td><td>Required</td></tr><tr><td><strong>Encrypted Only</strong></td><td><code>shellport server --no-totp</code></td><td>AES-256-GCM</td><td>Disabled</td><td>Required</td></tr><tr><td><strong>TOTP Only</strong></td><td><code>shellport server --no-secret</code></td><td>None</td><td>Required</td><td>Required</td></tr><tr><td><strong>Plaintext</strong></td><td><code>shellport server --no-secret --no-totp</code></td><td>None</td><td>Disabled</td><td>Required</td></tr></tbody></table><h3 id="mode-recommendations" tabindex="-1">Mode Recommendations <a class="header-anchor" href="#mode-recommendations" aria-label="Permalink to &quot;Mode Recommendations&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Use Case</th><th>Recommended Mode</th></tr></thead><tbody><tr><td>Default / Public internet</td><td>Full Security</td></tr><tr><td>Trusted internal network</td><td>Encrypted Only</td></tr><tr><td>VPN/Tailscale connection</td><td>TOTP Only</td></tr><tr><td>Local development only</td><td>Plaintext</td></tr></tbody></table><h2 id="known-limitations" tabindex="-1">Known Limitations <a class="header-anchor" href="#known-limitations" aria-label="Permalink to &quot;Known Limitations&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Understanding these limitations is important for secure deployment.</p></div><h3 id="no-forward-secrecy" tabindex="-1">No Forward Secrecy <a class="header-anchor" href="#no-forward-secrecy" aria-label="Permalink to &quot;No Forward Secrecy&quot;">​</a></h3><ul><li>If the session secret is compromised after the session ends, all historical traffic can be decrypted</li><li>Use over VPN/Tailscale for additional protection</li><li>Consider rotating secrets regularly</li></ul><h3 id="totp-secret-storage" tabindex="-1">TOTP Secret Storage <a class="header-anchor" href="#totp-secret-storage" aria-label="Permalink to &quot;TOTP Secret Storage&quot;">​</a></h3><ul><li>The TOTP pairing secret is stored in <code>~/.shellport-totp-secret</code></li><li>This file should be protected (chmod 600)</li><li>Loss of this file requires <code>--totp-reset</code> to re-pair</li></ul><h3 id="connection-approval-requires-terminal-access" tabindex="-1">Connection Approval Requires Terminal Access <a class="header-anchor" href="#connection-approval-requires-terminal-access" aria-label="Permalink to &quot;Connection Approval Requires Terminal Access&quot;">​</a></h3><ul><li>Someone with terminal access to the server must approve connections</li><li>Not suitable for fully remote/unattended deployments without VPN</li></ul><h2 id="security-checklist" tabindex="-1">Security Checklist <a class="header-anchor" href="#security-checklist" aria-label="Permalink to &quot;Security Checklist&quot;">​</a></h2><p>For production deployments:</p><ul><li>[ ] Keep TOTP enabled (default)</li><li>[ ] Keep approval mode enabled (default)</li><li>[ ] Use <code>--no-secret</code> only over VPN/Tailscale</li><li>[ ] Protect <code>~/.shellport-totp-secret</code> file</li><li>[ ] Use <code>--tailscale serve</code> or <code>--tailscale funnel</code> for public HTTPS</li><li>[ ] Review firewall rules (default port: 7681)</li><li>[ ] Consider IP allowlisting for sensitive deployments</li></ul>`,85)])])}const g=t(n,[["render",r]]);export{u as __pageData,g as default};
